import{_ as i,o as e,c as a,ae as o}from"./chunks/framework.C7FLYIpo.js";const p=JSON.parse('{"title":"TUI","description":"터미널 UI (TUI): 모든 머신에서 게이트웨이에 연결","frontmatter":{"title":"TUI","description":"터미널 UI (TUI): 모든 머신에서 게이트웨이에 연결"},"headers":[],"relativePath":"web/tui.md","filePath":"web/tui.md","lastUpdated":null}'),t={name:"web/tui.md"};function s(d,l,c,n,h,r){return e(),a("div",null,[...l[0]||(l[0]=[o('<h1 id="tui-터미널-ui" tabindex="-1">TUI (터미널 UI) <a class="header-anchor" href="#tui-터미널-ui" aria-label="Permalink to &quot;TUI (터미널 UI)&quot;">​</a></h1><h2 id="빠른-시작" tabindex="-1">빠른 시작 <a class="header-anchor" href="#빠른-시작" aria-label="Permalink to &quot;빠른 시작&quot;">​</a></h2><ol><li>게이트웨이를 시작하십시오.</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre></div><ol start="2"><li>TUI를 여십시오.</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre></div><ol start="3"><li>메시지를 입력하고 Enter를 누르십시오.</li></ol><p>원격 게이트웨이:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ws://</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">hos</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">por</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --token</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">gateway-toke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>게이트웨이가 비밀번호 인증을 사용하는 경우 <code>--password</code>를 사용하십시오.</p><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><ul><li>헤더: 연결 URL, 현재 에이전트, 현재 세션.</li><li>채팅 로그: 사용자 메시지, 어시스턴트 응답, 시스템 알림, 도구 카드.</li><li>상태 표시줄: 연결/실행 상태 (연결 중, 실행 중, 스트리밍, 대기 중, 오류).</li><li>푸터: 연결 상태 + 에이전트 + 세션 + 모델 + 생각/빠른/상세/추론 + 토큰 수 + 전달.</li><li>입력: 자동 완성이 있는 텍스트 편집기.</li></ul><h2 id="개념적-모델-에이전트-세션" tabindex="-1">개념적 모델: 에이전트 + 세션 <a class="header-anchor" href="#개념적-모델-에이전트-세션" aria-label="Permalink to &quot;개념적 모델: 에이전트 + 세션&quot;">​</a></h2><ul><li>에이전트는 고유한 슬러그입니다 (예: <code>main</code>, <code>research</code>). 게이트웨이가 목록을 노출합니다.</li><li>세션은 현재 에이전트에 속합니다.</li><li>세션 키는 <code>agent:&lt;agentId&gt;:&lt;sessionKey&gt;</code>로 저장됩니다. <ul><li><code>/session main</code>을 입력하면 TUI가 <code>agent:&lt;currentAgent&gt;:main</code>으로 확장합니다.</li><li><code>/session agent:other:main</code>을 입력하면 해당 에이전트 세션으로 명시적으로 전환합니다.</li></ul></li><li>세션 범위: <ul><li><code>per-sender</code> (기본값): 각 에이전트에 많은 세션이 있습니다.</li><li><code>global</code>: TUI가 항상 <code>global</code> 세션을 사용합니다 (선택기가 비어 있을 수 있음).</li></ul></li><li>현재 에이전트 + 세션은 항상 푸터에 표시됩니다.</li></ul><h2 id="전송-전달" tabindex="-1">전송 + 전달 <a class="header-anchor" href="#전송-전달" aria-label="Permalink to &quot;전송 + 전달&quot;">​</a></h2><ul><li>메시지는 게이트웨이로 전송됩니다. 프로바이더에 대한 전달은 기본적으로 꺼져 있습니다.</li><li>전달 켜기: <ul><li><code>/deliver on</code></li><li>또는 설정 패널</li><li>또는 <code>openclaw tui --deliver</code>로 시작</li></ul></li></ul><h2 id="선택기-오버레이" tabindex="-1">선택기 + 오버레이 <a class="header-anchor" href="#선택기-오버레이" aria-label="Permalink to &quot;선택기 + 오버레이&quot;">​</a></h2><ul><li>모델 선택기: 사용 가능한 모델을 나열하고 세션 재정의를 설정합니다.</li><li>에이전트 선택기: 다른 에이전트를 선택합니다.</li><li>세션 선택기: 현재 에이전트의 세션만 표시합니다.</li><li>설정: 전달, 도구 출력 확장 및 생각 가시성을 토글합니다.</li></ul><h2 id="키보드-단축키" tabindex="-1">키보드 단축키 <a class="header-anchor" href="#키보드-단축키" aria-label="Permalink to &quot;키보드 단축키&quot;">​</a></h2><ul><li>Enter: 메시지 전송</li><li>Esc: 활성 실행 중단</li><li>Ctrl+C: 입력 지우기 (두 번 누르면 종료)</li><li>Ctrl+D: 종료</li><li>Ctrl+L: 모델 선택기</li><li>Ctrl+G: 에이전트 선택기</li><li>Ctrl+P: 세션 선택기</li><li>Ctrl+O: 도구 출력 확장 토글</li><li>Ctrl+T: 생각 가시성 토글 (히스토리 다시 로드)</li></ul><h2 id="슬래시-명령" tabindex="-1">슬래시 명령 <a class="header-anchor" href="#슬래시-명령" aria-label="Permalink to &quot;슬래시 명령&quot;">​</a></h2><p>핵심:</p><ul><li><code>/help</code></li><li><code>/status</code></li><li><code>/agent &lt;id&gt;</code> (또는 <code>/agents</code>)</li><li><code>/session &lt;key&gt;</code> (또는 <code>/sessions</code>)</li><li><code>/model &lt;provider/model&gt;</code> (또는 <code>/models</code>)</li></ul><p>세션 제어:</p><ul><li><code>/think &lt;off|minimal|low|medium|high&gt;</code></li><li><code>/fast &lt;status|on|off&gt;</code></li><li><code>/verbose &lt;on|full|off&gt;</code></li><li><code>/reasoning &lt;on|off|stream&gt;</code></li><li><code>/usage &lt;off|tokens|full&gt;</code></li><li><code>/elevated &lt;on|off|ask|full&gt;</code> (별칭: <code>/elev</code>)</li><li><code>/activation &lt;mention|always&gt;</code></li><li><code>/deliver &lt;on|off&gt;</code></li></ul><p>세션 수명 주기:</p><ul><li><code>/new</code> 또는 <code>/reset</code> (세션 초기화)</li><li><code>/abort</code> (활성 실행 중단)</li><li><code>/settings</code></li><li><code>/exit</code></li></ul><p>다른 게이트웨이 슬래시 명령 (예: <code>/context</code>)은 게이트웨이로 전달되어 시스템 출력으로 표시됩니다. <a href="/openclaw-docs-ko/tools/slash-commands">슬래시 명령</a>을 참조하십시오.</p><h2 id="로컬-셸-명령" tabindex="-1">로컬 셸 명령 <a class="header-anchor" href="#로컬-셸-명령" aria-label="Permalink to &quot;로컬 셸 명령&quot;">​</a></h2><ul><li>라인 앞에 <code>!</code>를 붙여 TUI 호스트에서 로컬 셸 명령을 실행합니다.</li><li>TUI는 세션당 한 번 로컬 실행을 허용하라는 메시지를 표시합니다. 거부하면 세션에 대해 <code>!</code>가 비활성화된 상태로 유지됩니다.</li><li>명령은 TUI 작업 디렉토리의 새로운 비대화형 셸에서 실행됩니다 (영구적인 <code>cd</code>/env 없음).</li><li>로컬 셸 명령은 환경에서 <code>OPENCLAW_SHELL=tui-local</code>을 받습니다.</li><li>단독 <code>!</code>는 일반 메시지로 전송됩니다. 앞의 공백은 로컬 exec를 트리거하지 않습니다.</li></ul><h2 id="도구-출력" tabindex="-1">도구 출력 <a class="header-anchor" href="#도구-출력" aria-label="Permalink to &quot;도구 출력&quot;">​</a></h2><ul><li>도구 호출은 인수 + 결과가 있는 카드로 표시됩니다.</li><li>Ctrl+O로 축소/확장 보기 간 전환합니다.</li><li>도구가 실행되는 동안 부분 업데이트가 동일한 카드로 스트리밍됩니다.</li></ul><h2 id="터미널-색상" tabindex="-1">터미널 색상 <a class="header-anchor" href="#터미널-색상" aria-label="Permalink to &quot;터미널 색상&quot;">​</a></h2><ul><li>TUI는 어시스턴트 본문 텍스트를 터미널의 기본 전경색으로 유지하여 어두운 터미널과 밝은 터미널 모두 읽기 쉽게 합니다.</li><li>터미널이 밝은 배경을 사용하고 자동 감지가 잘못된 경우 <code>openclaw tui</code>를 시작하기 전에 <code>OPENCLAW_THEME=light</code>를 설정하십시오.</li><li>대신 원래의 어두운 팔레트를 강제하려면 <code>OPENCLAW_THEME=dark</code>를 설정하십시오.</li></ul><h2 id="히스토리-스트리밍" tabindex="-1">히스토리 + 스트리밍 <a class="header-anchor" href="#히스토리-스트리밍" aria-label="Permalink to &quot;히스토리 + 스트리밍&quot;">​</a></h2><ul><li>연결 시 TUI는 최신 히스토리를 로드합니다 (기본 200개 메시지).</li><li>스트리밍 응답은 최종화될 때까지 제자리에서 업데이트됩니다.</li><li>TUI는 더 풍부한 도구 카드를 위해 에이전트 도구 이벤트도 수신합니다.</li></ul><h2 id="연결-세부-정보" tabindex="-1">연결 세부 정보 <a class="header-anchor" href="#연결-세부-정보" aria-label="Permalink to &quot;연결 세부 정보&quot;">​</a></h2><ul><li>TUI는 <code>mode: &quot;tui&quot;</code>로 게이트웨이에 등록합니다.</li><li>재연결은 시스템 메시지를 표시합니다. 이벤트 간격이 로그에 표시됩니다.</li></ul><h2 id="옵션" tabindex="-1">옵션 <a class="header-anchor" href="#옵션" aria-label="Permalink to &quot;옵션&quot;">​</a></h2><ul><li><code>--url &lt;url&gt;</code>: 게이트웨이 WebSocket URL (구성 또는 <code>ws://127.0.0.1:&lt;port&gt;</code>가 기본값)</li><li><code>--token &lt;token&gt;</code>: 게이트웨이 토큰 (필요한 경우)</li><li><code>--password &lt;password&gt;</code>: 게이트웨이 비밀번호 (필요한 경우)</li><li><code>--session &lt;key&gt;</code>: 세션 키 (기본값: <code>main</code>, 또는 범위가 global인 경우 <code>global</code>)</li><li><code>--deliver</code>: 어시스턴트 응답을 프로바이더에 전달 (기본적으로 꺼짐)</li><li><code>--thinking &lt;level&gt;</code>: 전송을 위한 생각 레벨 재정의</li><li><code>--message &lt;text&gt;</code>: 연결 후 초기 메시지 전송</li><li><code>--timeout-ms &lt;ms&gt;</code>: 에이전트 타임아웃 (ms 단위, <code>agents.defaults.timeoutSeconds</code>가 기본값)</li><li><code>--history-limit &lt;n&gt;</code>: 로드할 히스토리 항목 (기본값 <code>200</code>)</li></ul><p>참고: <code>--url</code>을 설정하면 TUI는 구성 또는 환경 자격 증명으로 폴백하지 않습니다. <code>--token</code> 또는 <code>--password</code>를 명시적으로 전달하십시오. 명시적 자격 증명이 없는 것은 오류입니다.</p><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><p>메시지 전송 후 출력이 없는 경우:</p><ul><li>TUI에서 <code>/status</code>를 실행하여 게이트웨이가 연결되어 있고 대기/사용 중인지 확인하십시오.</li><li>게이트웨이 로그 확인: <code>openclaw logs --follow</code>.</li><li>에이전트가 실행될 수 있는지 확인: <code>openclaw status</code> 및 <code>openclaw models status</code>.</li><li>채팅 채널에서 메시지를 기대하는 경우 전달을 활성화하십시오 (<code>/deliver on</code> 또는 <code>--deliver</code>).</li></ul><h2 id="연결-문제-해결" tabindex="-1">연결 문제 해결 <a class="header-anchor" href="#연결-문제-해결" aria-label="Permalink to &quot;연결 문제 해결&quot;">​</a></h2><ul><li><code>disconnected</code>: 게이트웨이가 실행 중인지, <code>--url/--token/--password</code>가 올바른지 확인하십시오.</li><li>선택기에 에이전트 없음: <code>openclaw agents list</code>와 라우팅 구성을 확인하십시오.</li><li>세션 선택기 비어 있음: global 범위에 있거나 아직 세션이 없을 수 있습니다.</li></ul><h2 id="관련" tabindex="-1">관련 <a class="header-anchor" href="#관련" aria-label="Permalink to &quot;관련&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/web/control-ui">Control UI</a> — 웹 기반 제어 인터페이스</li><li><a href="/openclaw-docs-ko/cli/">CLI 참조</a> — 전체 CLI 명령 참조</li></ul>',48)])])}const k=i(t,[["render",s]]);export{p as __pageData,k as default};
